import{_ as t,o as d,c as a,a2 as o}from"./chunks/framework.C90q7Ucc.js";const h=JSON.parse('{"title":"会话、Provider 与配置工作流","description":"","frontmatter":{},"headers":[],"relativePath":"guide/session-workflows.md","filePath":"guide/session-workflows.md","lastUpdated":1781343910000}'),s={name:"guide/session-workflows.md"};function n(c,e,i,r,p,l){return d(),a("div",null,[...e[0]||(e[0]=[o(`<h1 id="会话、provider-与配置工作流" tabindex="-1">会话、Provider 与配置工作流 <a class="header-anchor" href="#会话、provider-与配置工作流" aria-label="Permalink to &quot;会话、Provider 与配置工作流&quot;">​</a></h1><p>这页从日常使用角度串起 IM 会话、agent/provider、tmux pane 查看和配置层级。完整命令索引见 <a href="./../product/commands">命令体系</a>，provider 设计说明见 <a href="./../product/runtime-providers">运行时与提供方</a>。</p><h2 id="核心概念" tabindex="-1">核心概念 <a class="header-anchor" href="#核心概念" aria-label="Permalink to &quot;核心概念&quot;">​</a></h2><p>CodeLark 的 IM 对话由三层组成：</p><table tabindex="0"><thead><tr><th>层级</th><th>含义</th><th>常用入口</th></tr></thead><tbody><tr><td>Chat</td><td>飞书私聊、群聊、话题或云文档评论入口。它只记录“这个聊天当前接到哪个 BridgeSession”。</td><td><code>/t</code>、<code>/t 1</code>、<code>/t unbind</code></td></tr><tr><td>BridgeSession</td><td>CodeLark 管理的一条工作会话，保存工作目录、当前 runtime、provider、模型和底层 thread 身份。</td><td><code>/new</code>、<code>/clear</code>、<code>/current</code></td></tr><tr><td>Runtime thread</td><td>Codex thread 或 Claude Code session，是底层 agent 自己的会话身份。</td><td><code>/t</code> 接管、<code>/his</code> 查看历史</td></tr></tbody></table><p><code>/runtime</code> 选择当前会话使用 Codex 还是 Claude Code。<code>/provider</code> 选择当前 runtime 的驱动方式，例如 SDK、pty 或 tmux。切换 runtime 不会清空另一个 runtime 已记住的 provider；同一个聊天可以记住 Codex 和 Claude 各自的 BridgeSession，来回切换时会尽量回到之前那条会话。</p><h2 id="推荐日常流程" tabindex="-1">推荐日常流程 <a class="header-anchor" href="#推荐日常流程" aria-label="Permalink to &quot;推荐日常流程&quot;">​</a></h2><p>新聊天里可以按这个顺序开始：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/status</span></span>
<span class="line"><span>/t</span></span>
<span class="line"><span>/t 1</span></span>
<span class="line"><span>/current</span></span></code></pre></div><p><code>/status</code> 看 bridge 和通道状态。<code>/t</code> 打开本地会话表；选择一条会话后发送 <code>/t 1</code> 或点击卡片中的选择项接管。<code>/current</code> 查看当前会话卡片，并在同一张卡片里改会话名、工作目录和当前 runtime 的配置。</p><p>如果要从空白会话开始：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/new my-task ~/work/project</span></span></code></pre></div><p>如果当前聊天已经在一个长对话里，但你想在同一个聊天上下文切到新对话：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/clear my-next-task ~/work/project</span></span></code></pre></div><p><code>/clear</code> 不会删除旧对话；之后仍可用 <code>/t</code> 找回并 attach。</p><h2 id="会话列表和下拉选框" tabindex="-1">会话列表和下拉选框 <a class="header-anchor" href="#会话列表和下拉选框" aria-label="Permalink to &quot;会话列表和下拉选框&quot;">​</a></h2><p><code>/t</code> 默认显示当前 runtime 最近 20 条本地会话，并发送一张表格卡片：</p><ul><li>会话下拉：选择表格中的某条本地会话，效果等同 <code>/t &lt;序号&gt;</code>。</li><li>数量下拉：切换显示 20、50 或 100 条，也可发送 <code>/t n 50</code>、<code>/t n 100</code>。</li><li>runtime 下拉：切换列表查看 Codex 或 Claude Code 会话，也可发送 <code>/t codex n 100</code> 或 <code>/t claude n 100</code>。</li></ul><p>表格首列会标出当前聊天正在绑定的会话，以及其他聊天已经绑定的会话。接管其他聊天绑定的会话时，如果目标还在运行会被拒绝；如果目标空闲，CodeLark 会先发确认卡片，确认后解绑原聊天并把会话 attach 到当前聊天。</p><p>常用 session 管理命令：</p><table tabindex="0"><thead><tr><th>操作</th><th>命令</th><th>说明</th></tr></thead><tbody><tr><td>attach 本地会话</td><td><code>/t 1</code></td><td>按当前 <code>/t</code> 表中的序号接管会话。</td></tr><tr><td>attach 指定会话</td><td><code>/t &lt;thread_id&gt;</code> 或 <code>/t &lt;bridge_id&gt;</code></td><td>也可用名称匹配，冲突时先回到 <code>/t</code> 用序号。</td></tr><tr><td>detach 当前聊天</td><td><code>/t unbind</code></td><td>当前聊天脱离原会话，并立即绑定到新的临时 BridgeSession；原会话保留，可再次 <code>/t</code> 接回。</td></tr><tr><td>临时会话</td><td><code>/t 0</code></td><td>切到隐藏的临时 BridgeSession。</td></tr><tr><td>重置临时会话</td><td><code>/t 0 reset</code></td><td>丢弃当前临时上下文并生成新的临时 BridgeSession。</td></tr><tr><td>归档当前本地会话</td><td><code>/t archive</code></td><td>归档当前绑定的本地 Codex/Claude 会话，并解除相关绑定。</td></tr><tr><td>归档指定会话</td><td><code>/t archive 1</code></td><td>按当前 runtime 的 <code>/t</code> 表序号归档。</td></tr><tr><td>重命名当前线程</td><td><code>/t rename &lt;名称&gt;</code></td><td>群聊通道会同步修改群名，并自动带 bot 前缀。</td></tr></tbody></table><h2 id="新建、清空和接回旧会话" tabindex="-1">新建、清空和接回旧会话 <a class="header-anchor" href="#新建、清空和接回旧会话" aria-label="Permalink to &quot;新建、清空和接回旧会话&quot;">​</a></h2><p><code>/new &lt;name&gt; [path]</code> 会创建新的 IM 群聊会话。未写 path 时继承当前会话目录；未绑定时使用全局默认工作目录。名称或路径包含空格时，用英文引号包起来：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/new &quot;前端 调试&quot; &quot;~/work/my project&quot;</span></span></code></pre></div><p><code>/clear [name] [path]</code> 在当前聊天里创建一个新对话并绑定过去，适合“同一个聊天继续做新任务”。如果当前任务仍在运行，或者 tmux TUI 追加输入还没有结束，CodeLark 会先要求确认是否终止旧对话。</p><p><code>/t unbind</code> 是 detach 当前聊天，而不是删除会话。detach 后直接发普通文本会进入新的临时 BridgeSession；想接回旧会话时，发送 <code>/t</code> 找到它再 <code>/t &lt;序号&gt;</code>。</p><h2 id="切换-agent-和-provider" tabindex="-1">切换 agent 和 provider <a class="header-anchor" href="#切换-agent-和-provider" aria-label="Permalink to &quot;切换 agent 和 provider&quot;">​</a></h2><p>切换 agent：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/runtime codex</span></span>
<span class="line"><span>/runtime claude</span></span></code></pre></div><p>切换 provider：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/provider</span></span>
<span class="line"><span>/p tmux</span></span>
<span class="line"><span>/p pty</span></span>
<span class="line"><span>/p sdk</span></span></code></pre></div><p>Codex 支持 <code>sdk</code>、<code>pty</code>、<code>tmux</code>。Claude Code 支持 <code>tmux</code>、<code>pty</code>、<code>sdk</code>，默认是 <code>tmux</code>。<code>/provider</code> 不带参数时会显示当前 runtime 的 provider 和可选值。</p><p><code>/current</code> 卡片顶部有 runtime 下拉，可以直接在 Codex 和 Claude Code 之间切换并刷新卡片。卡片表单保存时只更新当前显示 runtime 的配置项；例如切到 Claude Code 后保存，不会修改 Codex 的 sandbox 或 network 设置。</p><p>运行中不能随意切换 runtime/provider。遇到拒绝提示时，先等当前任务结束，或发送 <code>/stop</code> 停止当前任务，再切换。</p><h2 id="tmux-状态下输入和-pane-查看" tabindex="-1">tmux 状态下输入和 pane 查看 <a class="header-anchor" href="#tmux-状态下输入和-pane-查看" aria-label="Permalink to &quot;tmux 状态下输入和 pane 查看&quot;">​</a></h2><p>选择 tmux provider：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/p tmux</span></span></code></pre></div><p>之后普通文本会先进入同一个 BridgeSession 的 provider-owned tmux TUI。CodeLark 会等待 TUI ready；如果启动时出现 Codex update、trust、goal 或 permission 选择，会把选择卡片发到 IM，用户选择完成后再把原始输入转发进去。</p><p>查看当前 tmux pane：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/tmux-screen</span></span>
<span class="line"><span>/tmux-screen 120</span></span>
<span class="line"><span>/tmux-screen 120 5s</span></span>
<span class="line"><span>/tmux-screen stop</span></span></code></pre></div><p><code>/tmux-screen</code> 只查看当前绑定的 tmux session，不会自动恢复缺失的 provider session，也不会等待正在排队的普通对话。带 <code>5s</code> 会启动定时刷新，最低 3 秒；<code>stop</code> 停止当前聊天的刷新。</p><p>手动输入 tmux：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/tmux pwd</span></span>
<span class="line"><span>/tmux pwd&lt;Enter&gt;</span></span>
<span class="line"><span>/tmux-key &lt;C-c&gt;</span></span></code></pre></div><p><code>/tmux ...</code> 会把普通文本写入当前绑定的 tmux session，并按当前会话设置决定是否自动补 Enter。<code>/tmux-key ...</code> 用来发送控制键。发送后会自动截屏返回。</p><p>tmux 绑定和默认值：</p><table tabindex="0"><thead><tr><th>命令</th><th>说明</th></tr></thead><tbody><tr><td><code>/tmux-status</code></td><td>查看当前 tmux 绑定、展示行数和输入设置。</td></tr><tr><td><code>/tmux-switch</code></td><td>列出本机 tmux sessions。</td></tr><tr><td><code>/tmux-attach &lt;session&gt;</code></td><td>把当前 BridgeSession 绑定到已有 tmux session。</td></tr><tr><td><code>/tmux-new [session]</code></td><td>新建并绑定 tmux session；已存在则直接绑定。</td></tr><tr><td><code>/tmux-set lines &lt;1-500&gt;</code></td><td>设置 <code>/tmux</code> 和 <code>/tmux-screen</code> 默认展示行数。</td></tr><tr><td><code>/tmux-set enter on/off</code></td><td>设置 <code>/tmux ...</code> 是否自动补 Enter。</td></tr><tr><td><code>/tmux-set echo on/off</code></td><td>设置 <code>/tmux ...</code> 回复中是否回显本次输入。</td></tr></tbody></table><p><code>/tmux-set</code> 写的是当前 BridgeSession 的 session-level 配置。想修改全局默认展示行数，用 <code>/set tmuxCaptureLines &lt;1-500&gt;</code>。</p><h2 id="配置层级-home-level-和-chat-level" tabindex="-1">配置层级：home level 和 chat level <a class="header-anchor" href="#配置层级-home-level-和-chat-level" aria-label="Permalink to &quot;配置层级：home level 和 chat level&quot;">​</a></h2><p>CodeLark 的配置分两类理解最清楚：</p><table tabindex="0"><thead><tr><th>层级</th><th>写入位置</th><th>典型入口</th><th>生效范围</th></tr></thead><tbody><tr><td>home level</td><td><code>~/.codelark/config.toml</code></td><td><code>/set</code>、Web 工作台配置页</td><td>全局默认值和通道默认值。新会话会继承这些默认值。</td></tr><tr><td>chat/session level</td><td><code>~/.codelark/config/sessions/&lt;session-id&gt;.toml</code></td><td><code>/runtime</code>、<code>/provider</code>、<code>/model</code>、<code>/cd</code>、<code>/tmux-set</code>、<code>/current</code> 卡片</td><td>当前聊天绑定的 BridgeSession。只影响这条会话。</td></tr></tbody></table><p><code>/set</code> 打开的是 home level TOML 配置卡片，顶部下拉可切换：</p><ul><li>通用配置：默认 agent、默认工作目录、tmux 默认展示行数、tmux 自动回车、tmux 输入回显。</li><li>Codex：默认模型、YOLO 模式、provider、skip git repo check、sandbox、network、reasoning。</li><li>Claude：默认模型、YOLO 模式、provider、Claude executable、reasoning、空闲超时。</li><li>Bridge：UI 访问和流式状态提示。</li><li>通道配置（feishu-default）：历史消息数量、流式反馈、Markdown 反馈、群聊是否需要 @bot 等。</li></ul><p>也可以直接写单项：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/set runtime codex</span></span>
<span class="line"><span>/set defaultWorkspaceRoot ~/work</span></span>
<span class="line"><span>/set defaultProvider tmux</span></span>
<span class="line"><span>/set claudeProvider tmux</span></span>
<span class="line"><span>/set tmuxCaptureLines 80</span></span></code></pre></div><p>当前聊天的 runtime/provider/model/cwd 优先使用 session-level 覆盖。也就是说，<code>/set defaultProvider tmux</code> 会影响以后新建或没有覆盖的会话；已经在当前聊天里执行过 <code>/provider sdk</code> 的会话，会继续使用自己的 session-level provider，直到再次发送 <code>/provider ...</code> 或在 <code>/current</code> 卡片里保存新值。</p><h2 id="什么时候看哪张卡片" tabindex="-1">什么时候看哪张卡片 <a class="header-anchor" href="#什么时候看哪张卡片" aria-label="Permalink to &quot;什么时候看哪张卡片&quot;">​</a></h2><table tabindex="0"><thead><tr><th>目标</th><th>入口</th></tr></thead><tbody><tr><td>看 bridge、通道和当前绑定</td><td><code>/status</code></td></tr><tr><td>找本地 Codex/Claude 会话并 attach</td><td><code>/t</code></td></tr><tr><td>改当前会话名、cwd、runtime 配置</td><td><code>/current</code></td></tr><tr><td>改全局默认值和通道默认值</td><td><code>/set</code></td></tr><tr><td>看 tmux provider 的当前屏幕</td><td><code>/tmux-screen</code></td></tr><tr><td>看 pty provider 的当前屏幕</td><td><code>/pty-screen</code></td></tr><tr><td>查看最近模型消息历史</td><td><code>/his</code></td></tr></tbody></table><p>排障时先发 <code>/current</code> 确认当前聊天绑到了哪条 BridgeSession，再发 <code>/provider</code> 和 <code>/tmux-status</code> 确认 runtime/provider 与 tmux 绑定是否符合预期。</p>`,58)])])}const m=t(s,[["render",n]]);export{h as __pageData,m as default};
